+  const publishByName = new Map(workspacePackages.map((pkg) => [pkg.name, isPublishable(pkg)]));
+  const unpublishedWorkspaceNames = new Set(
+    [...publishByName.entries()].filter(([, publish]) => !publish).map(([name]) => name),
+  );
