   170	fn collect_recent_candidates() -> Vec<SessionCandidate> {
   171	    let mut candidates = Vec::new();
   172	    for location in discover_sessions() {
   173	        for path in location.paths {
   174	            let Ok(metadata) = std::fs::metadata(&path) else {
   175	                continue;
   176	            };
   177	            let Ok(modified) = metadata.modified() else {
   178	                continue;
   179	            };
   180	            candidates.push(SessionCandidate { path, modified });
   181	        }
   182	    }
   183	
   184	    candidates.sort_by_key(|candidate| Reverse(candidate.modified));
   185	    candidates.into_iter().take(SYNC_MAX_CANDIDATES).collect()
   186	}
