   265	fn commit_shas_from_reflog(repo_root: &Path, start_ts: i64, end_ts: i64) -> Vec<String> {
   266	    let git_dir_output = Command::new("git")
   267	        .arg("-C")
   268	        .arg(repo_root)
   269	        .arg("rev-parse")
   270	        .arg("--git-dir")
   271	        .output();
   272	    let Ok(git_dir_output) = git_dir_output else {
   273	        return Vec::new();
   274	    };
   275	    if !git_dir_output.status.success() {
   276	        return Vec::new();
   277	    }
   278	    let git_dir = String::from_utf8_lossy(&git_dir_output.stdout)
   279	        .trim()
   280	        .to_string();
   281	    if git_dir.is_empty() {
   282	        return Vec::new();
   283	    }
   284	
   285	    let git_dir_path = if Path::new(&git_dir).is_absolute() {
   286	        PathBuf::from(git_dir)
   287	    } else {
   288	        repo_root.join(git_dir)
   289	    };
   290	    let reflog_path = git_dir_path.join("logs").join("HEAD");
   291	    let raw = std::fs::read_to_string(reflog_path);
   292	    let Ok(raw) = raw else {
   293	        return Vec::new();
   294	    };
   295	
   296	    let mut seen = HashSet::new();
   297	    let mut commits = Vec::new();
   298	    for line in raw.lines() {
   299	        let Some((left, _)) = line.split_once('\t') else {
   300	            continue;
   301	        };
   302	        let mut parts = left.split_whitespace();
   303	        let _old = parts.next();
   304	        let Some(new_sha) = parts.next() else {
   305	            continue;
   306	        };
   307	        if new_sha.len() < 7 || !new_sha.chars().all(|ch| ch.is_ascii_hexdigit()) {
   308	            continue;
   309	        }
   310	        let mut tail = left.split_whitespace().rev();
   311	        let _tz = tail.next();
   312	        let Some(ts_raw) = tail.next() else {
   313	            continue;
   314	        };
   315	        let Ok(ts) = ts_raw.parse::<i64>() else {
   316	            continue;
   317	        };
   318	        if ts < start_ts || ts > end_ts {
   319	            continue;
   320	        }
   321	        if seen.insert(new_sha.to_string()) {
   322	            commits.push(new_sha.to_string());
   323	        }
   324	    }
   325	    commits
   326	}
