   328	fn session_commit_links(
   329	    repo_root: &Path,
   330	    branch_commits: &HashSet<String>,
   331	    session: &Session,
   332	    commit_hint: Option<&str>,
   333	) -> Vec<String> {
   334	    let created = session.context.created_at.timestamp();
   335	    let updated = session.context.updated_at.timestamp();
   336	    let (start, end) = if created <= updated {
   337	        (created, updated)
   338	    } else {
   339	        (updated, created)
   340	    };
   341	    let mut commits = commit_shas_from_reflog(repo_root, start, end)
   342	        .into_iter()
   343	        .filter(|sha| branch_commits.contains(sha))
   344	        .collect::<Vec<_>>();
   345	
   346	    if let Some(hint) = commit_hint {
   347	        if branch_commits.contains(hint) && !commits.iter().any(|sha| sha == hint) {
   348	            if let Some(hint_ts) = commit_time_unix(repo_root, hint) {
   349	                let window_start = start.saturating_sub(COMMIT_HINT_GRACE_SECONDS);
   350	                let window_end = end.saturating_add(COMMIT_HINT_GRACE_SECONDS);
   351	                if hint_ts >= window_start && hint_ts <= window_end {
   352	                    commits.push(hint.to_string());
   353	                }
   354	            }
   355	        }
   356	    }
   357	
   358	    commits
   359	}
