   845	    let pid_raw = match std::fs::read_to_string(pid_path) {
   846	        Ok(raw) => raw,
   847	        Err(err) => return DaemonStatus::Unreadable(format!("read {}: {err}", pid_path.display())),
   848	    };
   849	    let pid = match pid_raw.trim().parse::<u32>() {
   850	        Ok(pid) if pid > 0 => pid,
   851	        Ok(_) | Err(_) => {
   852	            return DaemonStatus::Unreadable(format!(
   853	                "invalid pid content in {}",
   854	                pid_path.display()
   855	            ));
   856	        }
   857	    };
   858	
   859	    if process_running(pid) {
   860	        DaemonStatus::Running(pid)
   861	    } else {
   862	        DaemonStatus::StalePid(pid)
   863	    }
   864	}
